@* Displays a single task card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeft() => await OnMoveLeftClicked.InvokeAsync(Task.Id);
    private async System.Threading.Tasks.Task OnMoveRight() => await OnMoveRightClicked.InvokeAsync(Task.Id);
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="Save" disabled="@saving">Save</button>
            <button class="btn btn-sm btn-secondary" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async System.Threading.Tasks.Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        saving = true;
        await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        saving = false;
        ResetForm();
    }

    private async System.Threading.Tasks.Task Cancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@* Summary statistics bar at the top of the board *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <span class="badge bg-primary fs-6">Total: @TotalCount</span>
    <span class="badge bg-secondary fs-6">To Do: @TodoCount</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @InProgressCount</span>
    <span class="badge bg-success fs-6">Done: @DoneCount</span>
    <span class="badge bg-danger fs-6">Overdue: @OverdueCount</span>
</div>

@code {
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async System.Threading.Tasks.Task OnInput(ChangeEventArgs e)
    {
        await SearchTextChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying task cards and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeftClicked="OnMoveLeftClicked"
                          OnMoveRightClicked="OnMoveRightClicked" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async System.Threading.Tasks.Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        showForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                TodoCount="TodoTasks.Count"
                InProgressCount="InProgressTasks.Count"
                DoneCount="DoneTasks.Count"
                OverdueCount="OverdueCount" />

    <BoardSearchBar SearchText="@searchText" SearchTextChanged="OnSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRightClicked="id => MoveTask(id, &quot;In Progress&quot;)"
                      OnTaskCreated="data => CreateTask(data, &quot;To Do&quot;)" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeftClicked="id => MoveTask(id, &quot;To Do&quot;)"
                      OnMoveRightClicked="id => MoveTask(id, &quot;Done&quot;)"
                      OnTaskCreated="data => CreateTask(data, &quot;In Progress&quot;)" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeftClicked="id => MoveTask(id, &quot;In Progress&quot;)"
                      OnTaskCreated="data => CreateTask(data, &quot;Done&quot;)" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    // Column groupings (unfiltered by search)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    // Search-filtered per column
    private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async System.Threading.Tasks.Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async System.Threading.Tasks.Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        searchText = value;
    }

    private async System.Threading.Tasks.Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == taskId ? t with { Status = newStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async System.Threading.Tasks.Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service creates with default status; update if the column differs
            if (created.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, status);
                created = created with { Status = status };
            }
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

